import{_ as a,c as e,o as s,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"首次启动: 掌握数据目录 | Antigravity Tools","description":"学习 Antigravity Tools 的数据目录位置与日志管理。掌握设置页打开数据目录、清理日志、托盘运行和开机自启，区分两类自动启动。","frontmatter":{"title":"首次启动: 掌握数据目录 | Antigravity Tools","sidebarTitle":"找到数据目录","subtitle":"首次启动必懂：数据目录、日志、托盘与自动启动","description":"学习 Antigravity Tools 的数据目录位置与日志管理。掌握设置页打开数据目录、清理日志、托盘运行和开机自启，区分两类自动启动。","tags":["首次启动","数据目录","日志","托盘","自动启动"],"prerequisite":["start-getting-started","start-installation"],"order":3},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}'),r={name:"zh/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function i(d,t,l,n,c,h){return s(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="首次启动必懂-数据目录、日志、托盘与自动启动" tabindex="-1">首次启动必懂：数据目录、日志、托盘与自动启动 <a class="header-anchor" href="#首次启动必懂-数据目录、日志、托盘与自动启动" aria-label="Permalink to &quot;首次启动必懂：数据目录、日志、托盘与自动启动&quot;">​</a></h1><p>Antigravity Tools 的很多&quot;看起来像魔法&quot;的能力（账号池、配额、监控、统计、后台运行），最后都要落到两样东西上：<strong>数据目录</strong>和<strong>日志</strong>。第一次跑起来就把这两块搞清楚，后面排障会省很多时间。</p><h2 id="什么是数据目录" tabindex="-1">什么是数据目录？ <a class="header-anchor" href="#什么是数据目录" aria-label="Permalink to &quot;什么是数据目录？&quot;">​</a></h2><p><strong>数据目录</strong>是 Antigravity Tools 在你本机保存状态的文件夹：账号 JSON、配额相关文件、日志文件，以及 Token Stats/Proxy Monitor 的 SQLite 数据库都放在这里。你做备份/迁移/排障时，只要先定位这个目录，基本就能找到权威数据源。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>知道 Antigravity Tools 的数据目录在哪（并能一键打开）</li><li>弄清哪些文件该备份，哪些是日志/缓存</li><li>需要排障时，能快速定位到日志与监控数据库</li><li>理解&quot;关闭窗口&quot;和&quot;退出程序&quot;的区别（托盘常驻）</li><li>区分两类自动启动：开机自启 vs 反代自动启动</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><ul><li>你想备份/迁移账号，但不知道账号到底保存在哪</li><li>UI 报错/反代调用失败，但你找不到日志</li><li>你把窗口关了，以为程序退出了，结果它还在后台跑</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li>你刚装好 Antigravity Tools，想确认&quot;数据放在哪&quot;</li><li>你准备换电脑/重装系统，想先把账号和统计数据备份出来</li><li>你要排查：OAuth 失败、刷新配额失败、反代启动失败、调用报 401/429</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>已安装并能打开 Antigravity Tools</li><li>你能进入 Settings 页面（右上角/侧边栏的设置入口）</li><li>你的系统账号有权限访问自己的 Home 目录</li></ul><div class="warning custom-block"><p class="custom-block-title">提醒</p><p>本课会告诉你哪些文件是&quot;真数据&quot;，但不建议你手动编辑这些文件。你要改配置，请优先在 UI 里改。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>先记住一句话：</p><p>&quot;<strong>数据目录是本地状态的单一真相源；日志是排障的第一入口。</strong>&quot;</p><p>Antigravity Tools 会在你的 Home 目录下创建 <code>.antigravity_tools</code> 数据目录，并把账号、日志、统计库等内容都放进去（目录不存在会自动创建）。</p><p>同时，它默认启用托盘：你关掉窗口时，程序不会立刻退出，而是隐藏到托盘，继续在后台运行。</p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-在设置页打开数据目录" tabindex="-1">第 1 步：在设置页打开数据目录 <a class="header-anchor" href="#第-1-步-在设置页打开数据目录" aria-label="Permalink to &quot;第 1 步：在设置页打开数据目录&quot;">​</a></h3><p><strong>为什么</strong> 你先把数据目录定位准，后面不管是备份还是排障，都有&quot;落点&quot;。</p><p>在 Antigravity Tools 里打开 Settings，然后切到 Advanced。</p><p>你会看到一块&quot;数据目录&quot;的只读输入框（它会显示真实路径），旁边有一个打开按钮。</p><p>点击打开按钮。</p><p><strong>你应该看到</strong>：系统文件管理器打开了一个目录，路径类似 <code>~/.antigravity_tools/</code>。</p><h3 id="第-2-步-确认你的数据目录路径-跨系统" tabindex="-1">第 2 步：确认你的数据目录路径（跨系统） <a class="header-anchor" href="#第-2-步-确认你的数据目录路径-跨系统" aria-label="Permalink to &quot;第 2 步：确认你的数据目录路径（跨系统）&quot;">​</a></h3><p><strong>为什么</strong> 你后续写脚本备份、或者在命令行里排查问题时，得知道这个目录在你系统上的实际路径。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-eL4Md" id="tab-3lkA9M6" checked><label data-title="macOS/Linux" for="tab-3lkA9M6">macOS/Linux</label><input type="radio" name="group-eL4Md" id="tab-alpA38o"><label data-title="Windows" for="tab-alpA38o">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>你应该看到</strong>：目录存在（如果你第一次打开设置页，目录会被自动创建）。</p><h3 id="第-3-步-认识数据目录里的-关键文件" tabindex="-1">第 3 步：认识数据目录里的&quot;关键文件&quot; <a class="header-anchor" href="#第-3-步-认识数据目录里的-关键文件" aria-label="Permalink to &quot;第 3 步：认识数据目录里的&quot;关键文件&quot;&quot;">​</a></h3><p><strong>为什么</strong> 不是所有文件都值得备份。先把&quot;哪些是账号数据&quot;&quot;哪些是统计库/日志&quot;分清。</p><p>下面这些文件名来自项目源码，都是固定的：</p><table tabindex="0"><thead><tr><th>你会看到的内容</th><th>用途</th><th>你需要关心什么</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>账号索引（包含账号列表/当前账号）</td><td>迁移账号时建议一起备份</td></tr><tr><td><code>accounts/</code></td><td>每个账号一个 <code>*.json</code> 文件</td><td>这是账号数据主体</td></tr><tr><td><code>logs/</code></td><td>应用日志目录</td><td>排障优先看这里</td></tr><tr><td><code>token_stats.db</code></td><td>Token Stats 的 SQLite 数据库</td><td>你在 Token Stats 页看到的数据来自它</td></tr><tr><td><code>proxy_logs.db</code></td><td>Proxy Monitor 的 SQLite 数据库</td><td>你在 Monitor 页看到的请求日志来自它</td></tr><tr><td><code>warmup_history.json</code></td><td>Smart Warmup 的本地历史记录</td><td>主要用于避免重复 warmup</td></tr><tr><td><code>update_settings.json</code></td><td>更新检查设置（自动检查/间隔等）</td><td>一般不需要手动动它</td></tr></tbody></table><p><strong>你应该看到</strong>：至少有 <code>logs/</code> 目录；如果你还没添加账号，<code>accounts.json</code>/<code>accounts/</code> 可能还没出现。</p><h3 id="第-4-步-把日志位置记牢-排障靠它" tabindex="-1">第 4 步：把日志位置记牢（排障靠它） <a class="header-anchor" href="#第-4-步-把日志位置记牢-排障靠它" aria-label="Permalink to &quot;第 4 步：把日志位置记牢（排障靠它）&quot;">​</a></h3><p><strong>为什么</strong> UI 的错误提示通常只给&quot;现象&quot;，真正的失败原因（例如请求失败、文件读写失败）往往在日志里。</p><p>Antigravity Tools 会把日志写到数据目录下的 <code>logs/</code>。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-tnwKo" id="tab-jK_b5MT" checked><label data-title="macOS/Linux" for="tab-jK_b5MT">macOS/Linux</label><input type="radio" name="group-tnwKo" id="tab-q56TAU5"><label data-title="Windows" for="tab-q56TAU5">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>你应该看到</strong>：目录下存在按天滚动的日志文件（文件名以 <code>app.log</code> 开头）。</p><h3 id="第-5-步-需要-清空日志-时-用设置页的一键清理" tabindex="-1">第 5 步：需要&quot;清空日志&quot;时，用设置页的一键清理 <a class="header-anchor" href="#第-5-步-需要-清空日志-时-用设置页的一键清理" aria-label="Permalink to &quot;第 5 步：需要&quot;清空日志&quot;时，用设置页的一键清理&quot;">​</a></h3><p><strong>为什么</strong> 有些问题你只想复现一次，然后把那次的日志单独留下来；这时先清空日志会更好对比。</p><p>在 Settings -&gt; Advanced 里，找到日志区域，点击&quot;清理日志&quot;。</p><p><strong>你应该看到</strong>：弹出确认框；确认后提示清理成功。</p><div class="tip custom-block"><p class="custom-block-title">你会担心的两件事</p><ul><li>日志会自动做&quot;按天滚动&quot;，并在启动时尝试清理超过 7 天的旧日志。</li><li>&quot;清理日志&quot;会把日志文件截断为 0 字节，方便正在运行的进程继续写同一个文件句柄。</li></ul></div><h3 id="第-6-步-弄清-关闭窗口-和-退出程序-的区别-托盘" tabindex="-1">第 6 步：弄清&quot;关闭窗口&quot;和&quot;退出程序&quot;的区别（托盘） <a class="header-anchor" href="#第-6-步-弄清-关闭窗口-和-退出程序-的区别-托盘" aria-label="Permalink to &quot;第 6 步：弄清&quot;关闭窗口&quot;和&quot;退出程序&quot;的区别（托盘）&quot;">​</a></h3><p><strong>为什么</strong> Antigravity Tools 默认启用托盘；你点窗口右上角关闭时，程序会隐藏到托盘继续运行。如果你以为它退出了，很容易出现&quot;端口还在占用/后台还在跑&quot;的错觉。</p><p>你可以用这个小流程确认：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>操作：关闭窗口（不是退出）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  第 1 步                第 2 步                             │</span></span>
<span class="line"><span>│  点击窗口关闭       →   去系统托盘/菜单栏找图标              │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你应该看到：托盘图标仍然存在，点它可以重新显示窗口。</span></span></code></pre></div><p>托盘菜单里还有两个常用动作（不走 UI 的时候很方便）：</p><ul><li>切换账号：切换到下一个账号</li><li>刷新配额：刷新当前账号配额（同时会通知前端刷新显示）</li></ul><h3 id="第-7-步-设置开机自启-让它启动后自动最小化" tabindex="-1">第 7 步：设置开机自启（让它启动后自动最小化） <a class="header-anchor" href="#第-7-步-设置开机自启-让它启动后自动最小化" aria-label="Permalink to &quot;第 7 步：设置开机自启（让它启动后自动最小化）&quot;">​</a></h3><p><strong>为什么</strong> 如果你希望它像&quot;常驻服务&quot;一样工作（托盘常驻 + 后台刷新），开机自启会省掉每次手动打开。</p><p>在 Settings -&gt; General 里找到&quot;开机自动启动&quot;，选择启用。</p><p><strong>你应该看到</strong>：切换后提示启用成功；下次开机启动时会带上 <code>--minimized</code> 参数运行。</p><div class="info custom-block"><p class="custom-block-title">两类&quot;自动启动&quot;，别搞混</p><table tabindex="0"><thead><tr><th>名称</th><th>指的是什么</th><th>证据</th></tr></thead><tbody><tr><td>开机自启</td><td>电脑启动后自动启动 Antigravity Tools（桌面应用本身）</td><td>启动参数包含 <code>--minimized</code>，并提供 <code>toggle_auto_launch</code> 命令</td></tr><tr><td>反代自动启动</td><td>Antigravity Tools 启动后，如果配置 <code>proxy.auto_start=true</code>，会尝试自动启动本地反代服务</td><td>应用启动时读取配置并 <code>start_proxy_service(...)</code></td></tr></tbody></table></div><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] 你能在 Settings -&gt; Advanced 看到数据目录的真实路径</li><li>[ ] 你能打开数据目录，并大致认得 <code>accounts.json</code>、<code>accounts/</code>、<code>logs/</code>、<code>token_stats.db</code>、<code>proxy_logs.db</code></li><li>[ ] 你知道日志在 <code>logs/</code> 下，并会用命令行快速查看</li><li>[ ] 你知道关闭窗口后程序仍在托盘，退出要用托盘菜单的 Quit</li><li>[ ] 你能区分&quot;开机自启&quot;和&quot;反代自动启动&quot;</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>你可能会怎么做（❌）</th><th>推荐做法（✓）</th></tr></thead><tbody><tr><td>找不到数据目录</td><td>在系统里乱搜 App 的安装目录</td><td>直接去 Settings -&gt; Advanced 看&quot;数据目录&quot;并一键打开</td></tr><tr><td>关掉窗口以为退出了</td><td>点窗口关闭后就去改配置/换端口</td><td>先看托盘图标是否还在；要退出用托盘 Quit</td></tr><tr><td>日志太多不好排查</td><td>一边复现问题一边翻旧日志</td><td>先&quot;清理日志&quot;，再复现一次，最后只看这次的日志文件</td></tr><tr><td>想改账号数据</td><td>手动编辑 <code>accounts/*.json</code></td><td>用 UI 的导入/导出/迁移流程（下一节相关章节会讲）</td></tr></tbody></table><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>数据目录固定在 Home 下的 <code>.antigravity_tools</code>（macOS/Linux 下通常表现为隐藏目录），账号/日志/统计库都在这里</li><li>日志目录是 <code>logs/</code>，排障时优先看；需要时可以在设置页一键清理</li><li>关闭窗口会隐藏到托盘继续运行；要彻底退出用托盘 Quit</li><li>自动启动有两类：开机自启（应用）和反代自动启动（Proxy）</li></ul><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../add-account/">添加账号：OAuth/Refresh Token 双通道与最佳实践</a></strong>。</p></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>数据目录位置（<code>~/.antigravity_tools</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>账号索引与账号文件目录（<code>accounts.json</code> / <code>accounts/</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>日志目录与按天滚动（<code>logs/</code> + <code>app.log</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>清理日志（截断文件）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>设置页展示数据目录 + 一键打开</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L525-L576" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>525-576</td></tr><tr><td>设置页一键清理日志（按钮 + 弹窗逻辑）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L127-L135" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>127-135</td></tr><tr><td>设置页一键清理日志（Advanced tab 按钮）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L732-L747" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>732-747</td></tr><tr><td>托盘菜单与点击事件（切换账号/刷新/显示/退出）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>开机自启开关（<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>一键打开数据目录 / 获取路径 / 清理日志命令</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Token Stats 数据库文件名（<code>token_stats.db</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Proxy Monitor 数据库文件名（<code>proxy_logs.db</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>Warmup 历史文件名（<code>warmup_history.json</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L14-L17" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>14-17</td></tr><tr><td>更新设置文件名（<code>update_settings.json</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>反代自动启动（<code>proxy.auto_start=true</code> 时启动服务）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L107-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>107-126</td></tr></tbody></table></details><h2 id="下一课预告-1" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告-1" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../add-account/">添加账号：OAuth/Refresh Token 双通道与最佳实践</a></strong>。</p><p>你会学到：</p><ul><li>什么时候用 OAuth，什么时候直接用 refresh_token</li><li>回调失败与拿不到 refresh_token 时怎么处理</li><li>怎么批量导入 refresh_token 快速建号池</li></ul></blockquote>`,69)])])}const g=a(r,[["render",i]]);export{u as __pageData,g as default};
